// // Asynchronous reset causes the flip-flop to hold its current value on the rising edge of the clock
module d_flip_flop(
    input       clk,
    input       rst,
    input       d,
    output reg  q
);

always @(posedge clk or posedge rst) begin
    if (rst)
        q <= 1'b0;
    else
        q <= d;
end

endmodule
